int longest_palindrome_length(const string& s) {
    unordered_map<char, int> freq;
    for (char ch : s) {
        freq[ch]++;
    }

    int length = 0;
    bool odd_found = false;

    for (const auto& pair : freq) {
        if (pair.second % 2 == 0) {
            length += pair.second;
        } else {
            length += pair.second - 1;
            odd_found = true;
        }
    }
    if (odd_found) {
        length += 1;
    }

    return length;
}

