code.C:
int longest_palindrome_length(const char* s) {
    int freq[256] = {0}; // Array to store frequency of all possible ASCII characters
    int length = 0;
    int odd_found = 0;

    // Calculate the frequency of each character
    for (int i = 0; s[i] != '\0'; i++) {
        freq[(unsigned char)s[i]]++;
    }

    // Compute the longest palindrome length
    for (int i = 0; i < 256; i++) {
        if (freq[i] % 2 == 0) {
            length += freq[i];
        } else {
            length += freq[i] - 1;
            odd_found = 1;
        }
    }

    // If there's an odd frequency character, add 1 to the length
    if (odd_found) {
        length += 1;
    }

    return length;
}

