    const freq = new Map();
    let length = 0;
    let oddFound = false;

    // Count frequency of each character
    for (const char of s) {
        freq.set(char, (freq.get(char) || 0) + 1);
    }

    // Calculate the longest palindrome length
    for (const count of freq.values()) {
        if (count % 2 === 0) {
            length += count;
        } else {
            length += count - 1;
            oddFound = true;
        }
